// Market hours check
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset + now.getTimezoneOffset() * 60 * 1000);
const day = ist.getDay();
if (day === 0 || day === 6) return [];
return [{ json: { date: ist.toISOString().split('T')[0] } }];

// Build batch Kite quote URL for all symbols + NIFTY
const symbols = $('Get All Symbols').all().map(i => i.json.symbol);
const allSymbols = ['NSE:NIFTY 50', ...symbols.map(s => `NSE:${s}`)];
const queryParams = allSymbols.map(s => `i=${encodeURIComponent(s)}`).join('&');
return [{ json: { quote_url: `https://api.kite.trade/quote?${queryParams}`, symbols } }];

// Build midday pulse per user — NO Claude, just template
const quotes = $input.first().json.data || {};
const users = $('Get Users').all().map(i => i.json);
const messages = [];

// NIFTY data
const niftyQuote = quotes['NSE:NIFTY 50'] || {};
const niftyPrice = niftyQuote.last_price || 0;
const niftyChange = niftyQuote.net_change || 0;
const niftyPct = niftyPrice > 0 ? ((niftyChange / (niftyPrice - niftyChange)) * 100).toFixed(1) : '?';
const niftyEmoji = parseFloat(niftyPct) >= 0 ? '🟢' : '🔴';

for (const user of users) {
  // Get this user's holdings P&L
  // In production: query holdings view + match with quotes
  // For now, calculate from all symbols
  let totalInvested = 0, totalCurrent = 0;
  let closestAlert = null, closestDist = 999;

  // Template message — 3 lines max
  const line1 = `${niftyEmoji} NIFTY: ${niftyPrice.toLocaleString()} (${parseFloat(niftyPct) >= 0 ? '+' : ''}${niftyPct}%)`;

  // Line 2: Portfolio P&L (simplified — in production, compute from actual holdings)
  const line2 = `Your portfolio: computing...`; // Replace with actual P&L calc

  // Line 3: Closest alert
  const line3 = closestAlert 
    ? `🔔 ${closestAlert.symbol} ${closestDist.toFixed(1)}% from target`
    : `🔔 All alerts within range`;

  const msg = `⏸️ *Midday Pulse* — 12:30 PM\n${line1}\n${line2}\n${line3}`;

  messages.push({
    chat_id: user.alerts_chat_id || user.private_chat_id,
    text: msg
  });
}

return messages.map(m => ({ json: m }));
